 1	import { FormSection, Text, FormGroup } from "@patternfly/react-core";
 2	import { useFormikContext } from "formik";
 3	import * as React from "react";
 4	import { getDefaultRemediator } from "../../../../data/remediator";
 5	import { NodeHealthCheckFormValues } from "../../../../data/types";
 6	import { useNodeHealthCheckTranslation } from "../../../../localization/useNodeHealthCheckTranslation";
 7	import CheckboxField from "../../../shared/CheckboxField";
 8	import RemediatorField from "./RemediatorField";
 9	import RemediatorsArrayField from "./RemediatorsArrayField";
10	import HelpIcon from "../../../shared/HelpIcon";
11	
12	const UseEscalatingField = () => {
13	  const { t } = useNodeHealthCheckTranslation();
14	  return (
15	    <CheckboxField
16	      name="formData.useEscalating"
17	      label={t("Use escalating remediations")}
18	    />
19	  );
20	};
21	
22	const RemediationTemplateField = () => {
23	  const { t } = useNodeHealthCheckTranslation();
24	  const { values, setFieldValue } =
25	    useFormikContext<NodeHealthCheckFormValues>();
26	
27	  // Initialize with default remediator if not set
28	  React.useEffect(() => {
29	    const defaultRemediator = getDefaultRemediator();
30	    if (!values.formData.remediator) {
31	      setFieldValue("formData.remediator", defaultRemediator);
32	    }
33	    if (
34	      !values.formData.escalatingRemediations?.length &&
35	      values.formData.useEscalating
36	    ) {
37	      setFieldValue("formData.escalatingRemediations", [defaultRemediator]);
38	    }
39	  }, [
40	    values.formData.remediator,
41	    values.formData.escalatingRemediations,
42	    values.formData.useEscalating,
43	    setFieldValue,
44	  ]);
45	  const helpText = t(
46	    "A reference to a remediation template resource. If a node needs remediation the controller will create an object from this template and then it should be picked up by a remediation provider. Multiple escalating remediation templates can be configured by clicking the 'Use escalating remediations' checkbox."
47	  );
48	
49	  const titleWithHelp = (
50	    <>
51	      {t("Remediation template")} <HelpIcon helpText={helpText} />
52	    </>
53	  );
54	
55	  return (
56	    <FormSection title={titleWithHelp} titleElement="h2">
57	      <FormGroup>
58	        <UseEscalatingField />
59	        {!values.formData.useEscalating && (
60	          <RemediatorField fieldName={"formData.remediator"} />
61	        )}
62	        {values.formData.useEscalating && (
63	          <>
64	            <Text>
65	              {t(
66	                "Rearrange the templates using drag and drop or by editing the 'Order' field. The remediations will be executed in the specified order."
67	              )}
68	            </Text>
69	            <RemediatorsArrayField />
70	          </>
71	        )}
72	      </FormGroup>
73	    </FormSection>
74	  );
75	};
76	
77	export default RemediationTemplateField;

